def combine(work, new_dir):
    # We need to fix the order of the texts that make up a particular work.
    texts = natsort.os_sorted(work_to_books[work])
    with open(os.path.join(new_dir, work + ".txt"), "w", encoding="utf-8") as combined_work:
        for text in texts:
            with open(os.path.join(corpus_dir, text), "r", encoding="utf-8") as single_text:
                combined_work.write(single_text.read())

works_too_short = []
for work, texts in work_to_books.items():
    sizes = sorted([os.path.getsize(os.path.join(corpus_dir, text)) // 1024 for text in texts])
    num_texts = len(sizes)
    if num_texts > 1:
        median_size = sizes[num_texts // 2] if num_texts % 2 == 1 else (sizes[num_texts // 2] + sizes[num_texts // 2 - 1]) / 2
        if median_size < threshold:
            works_too_short.append(work)
#print(works_too_short)
#print(len(works_too_short)) # 1281

os.mkdir(new_dir)
len_works_too_short = len(works_too_short)
for i, work in enumerate(works_too_short):
    combine(work, new_dir)
    print(f"Reached {work}")
    print(f"Combined {round(i / len_works_too_short * 100, 2)}%")
    print()

# Move to new folder to create "new" corpus.
texts_too_short = set([text for work in works_too_short for text in work_to_books[work]])
remaining_corpus_files = set(original_files).difference(texts_too_short) 
for text in remaining_corpus_files:
    shutil.copy2(os.path.join(corpus_dir, text), new_dir)